  // (icmp eq/ne (and (add nsw A, -1), Msk), 0) with range(A) <= u Msk + 1
  //    -> (icmp ne/eq (and A, ~Msk), 0)
  // This follows the logic of the above but handles the complement mask.
  // For example, (arg + -1) & -3 == 0 with arg in [0, 4)
  // becomes arg & 1 != 0.
  {
    Value *A;
    const APInt *Msk;
    if (C.isZero() &&
        match(And,
              m_And(m_OneUse(m_NSWAdd(m_Value(A), m_AllOnes())), m_APInt(Msk))) &&
        (*Msk).isNegative() && Pred == ICmpInst::ICMP_EQ) {
      // Check if A is range-limited such that (A + -1) & Msk == 0
      // is equivalent to A & ~Msk != 0.
      // Specifically, we need range(A) <= u (-Msk) + 1 for this fold to be valid.
      const ConstantRange &A_CR = computeConstantRange(A, /*ForSigned=*/false);
      unsigned Width = A_CR.getBitWidth();
      APInt UpperBound = (-(*Msk)) + 1;
      if (UpperBound.isIntN(Width)) {
        ConstantRange ValidRange(APInt::getZero(Width), UpperBound);
        if (ValidRange.contains(A_CR)) {
          // Use UpperBound - 1 = -Msk as the mask, not ~Msk.
          // For example, with Msk = -3 (0xFD for i8):
          //   ~Msk = 0x02 = 2 (wrong mask)
          //   -Msk = 0x03 = 3, UpperBound - 1 = 3 (correct mask for range [0,4))
          APInt Mask = UpperBound - 1;
          Value *ComplementAnd =
              Builder.CreateAnd(A, ConstantInt::get(A->getType(), Mask));
          return new ICmpInst(ICmpInst::ICMP_NE, ComplementAnd,
                              Constant::getNullValue(A->getType()));
        }
      }
    }
  }
EOF"}

